import{_ as e,c as i,a,o as n}from"./app-CEcM0piI.js";const l={};function d(t,s){return n(),i("div",null,s[0]||(s[0]=[a(`<p>自己定义的指令，可以封装一些dom操作，扩展额外功能</p><p>指令的钩子函数有两个:</p><ul><li>inserted会在指令所在元素被插入到页面中时触发</li><li>update会在指令的值修改的时候触发</li></ul><ol><li>全局注册</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Vue.directive()&#39;指令名&#39;,{</span></span>
<span class="line"><span>	&quot;inserted&quot;(el){</span></span>
<span class="line"><span>		//可以对 el标签，扩展额外功能</span></span>
<span class="line"><span>		el.focus()</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="2"><li>局部注册</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>directives:{</span></span>
<span class="line"><span>	&#39;指令名&quot;：{</span></span>
<span class="line"><span>		inserted () {</span></span>
<span class="line"><span>			//可以对 el标签，扩展额外功能</span></span>
<span class="line"><span>			el.focus()</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="插槽" tabindex="-1"><a class="header-anchor" href="#插槽"><span>插槽</span></a></h1><p>让组件内部的一些结构支持自定义</p><h3 id="匿名插槽" tabindex="-1"><a class="header-anchor" href="#匿名插槽"><span>匿名插槽</span></a></h3><p>在定义组件的时候使用<code>&lt;slot&gt;&lt;/slot&gt;</code>标签占位 在使用的时候将插入的内容使用自定义的标签报告就会把内容插入到slot的位置了</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;MyDialog&gt;内容&lt;/MyDialog&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="具名插槽" tabindex="-1"><a class="header-anchor" href="#具名插槽"><span>具名插槽</span></a></h3><p>匿名插槽只有一个占位,如果有多个需要插槽的地方可以使用具名插槽 若要定义具名插槽也是使用slot标签,不过需要加上name属性作以区分</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;div&gt;</span></span>
<span class="line"><span>	&lt;slot name=&quot;a&quot;&gt;&lt;/slot&gt;</span></span>
<span class="line"><span>	&lt;slot name=&quot;b&quot;&gt;&lt;/slot&gt;</span></span>
<span class="line"><span>&lt;/div&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在使用时需要用template标签包裹内容,并使用v-slot命令表示插入哪个插槽中</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;MyDialog&gt;</span></span>
<span class="line"><span>	&lt;template v-slot:a&gt;</span></span>
<span class="line"><span>		大标题</span></span>
<span class="line"><span>	&lt;/template&gt;</span></span>
<span class="line"><span>	&lt;template v-slot:a&gt;</span></span>
<span class="line"><span>		内容文本</span></span>
<span class="line"><span>	&lt;/template&gt;</span></span>
<span class="line"><span>&lt;/MyDialog&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>v-slot可使用<code>#</code>代替</p><h3 id="默认值" tabindex="-1"><a class="header-anchor" href="#默认值"><span>默认值</span></a></h3><p>要将插槽设置默认值只需要将值放在slot标签内即可</p><h3 id="作用域插槽" tabindex="-1"><a class="header-anchor" href="#作用域插槽"><span>作用域插槽</span></a></h3><p>定义 slot插槽的同时是可以传值的。给插槽上可以绑定数据将来使用组件时可以用</p><p>基本使用步骤：</p><ol><li>给slot标签，以添加属性的方式传值</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;slot :id=&quot;item.id&quot; msg=&quot;测试文本&quot;&gt;&lt;/slot&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="2"><li>所有添加的属性,都会被收集到一个对象中</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>{ id: 3, msg:测试文本’}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="3"><li>在template中,通过E#插槽名=&quot;obj&quot;接收，默认插槽名为default</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;MyTable :list=&quot;list&quot;&gt;</span></span>
<span class="line"><span>	&lt;template #default=&quot;obj&quot;&gt;</span></span>
<span class="line"><span>		&lt;button @click=&quot;del(obj.id)&quot;&gt;删除&lt;/button&gt;</span></span>
<span class="line"><span>	&lt;/template&gt;</span></span>
<span class="line"><span>&lt;/MyTable&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="路由" tabindex="-1"><a class="header-anchor" href="#路由"><span>路由</span></a></h1><p>修改地址栏路径时，切换显示匹配的组件</p><p>需要自己手动下载 vue2对应的时vuerouter3.x,vuex3.x vue3对应的时vuerouter4.x,vuex4.x</p><p>配置使用环境</p><ol><li>下载</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>npm add vue-router@3.6.5 -g</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="2"><li>引入</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>import VueRouter from &#39;vue-router&#39;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="3"><li>安装注册</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Vue.use(VueRouter)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="4"><li>为组件配置路由规则</li></ol><ul><li>创建需要的组件(views目录)，配置路由规则 创建的路由对象是空的,要想使用还需要添加路由规则</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>import Find from &#39;./views/Find.vue&#39;</span></span>
<span class="line"><span>import My from &#39;./views/My.vue&#39;</span></span>
<span class="line"><span>import Friend from &#39;./views/Friend.vue&#39;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>const router = new VueRouter({</span></span>
<span class="line"><span>	routes:[</span></span>
<span class="line"><span>		{path:&#39;/find&#39;,component: Find },</span></span>
<span class="line"><span>		{path:&#39;/my&#39;，component:My },</span></span>
<span class="line"><span>		{path:&#39;/friend&#39;，component:Friend }</span></span>
<span class="line"><span>	]</span></span>
<span class="line"><span>)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>配置导航，配置路由出口（路径匹配的组件显示的位置) router-view是一个占位标签,用于加载配置路由的组件</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;div class=&quot;footer_wrap&quot;&gt;</span></span>
<span class="line"><span>	&lt;a href=&quot;#/find&quot;&gt;发现音乐&lt;/a&gt;</span></span>
<span class="line"><span>	&lt;a href=&quot;#/my&quot;&gt;我的音乐&lt;/a&gt;</span></span>
<span class="line"><span>	&lt;a href=&quot;#/friend&quot;&gt;朋友&lt;/a&gt;</span></span>
<span class="line"><span>&lt;/div&gt;</span></span>
<span class="line"><span>&lt;div class=&quot;top&quot;&gt;</span></span>
<span class="line"><span>	&lt;router-view&gt;&lt;/router-view&gt;</span></span>
<span class="line"><span>&lt;/div&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="5"><li>注入，将路由对象注入到newVue实例中，建立关联</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>new Vue({</span></span>
<span class="line"><span>	render: h =&gt; h(App)</span></span>
<span class="line"><span>	router:router</span></span>
<span class="line"><span>}).$mount(&#39;#app&#39;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="路由的封装抽离" tabindex="-1"><a class="header-anchor" href="#路由的封装抽离"><span>路由的封装抽离</span></a></h2><p>若所有路由规则都配置在main.js中项目大了后就不好维护 可以分类管理路由规则,将路由规则放到router文件夹中,再在main.js中导入</p><p><strong>导包路径</strong> 可以使用@符代表当前目录的src目录</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>import Find from &#39;@/views/Find&#39;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="声明式导航" tabindex="-1"><a class="header-anchor" href="#声明式导航"><span>声明式导航</span></a></h2><p>vue-router提供了一个全局组件router-link(取代a 标签)</p><ol><li>能跳转，配置 to 属性指定路径(必须）。本质还是a标签，to 无需#</li><li>能高亮，默认就会提供高亮类名，可以直接设置高亮样式</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;div class=&quot;footer_wrap&quot;</span></span>
<span class="line"><span>	&lt;router-link to=&quot;/find&quot;&gt;发现音乐&lt;/router-link&gt;</span></span>
<span class="line"><span>	&lt;router-link to=&quot;/my&quot;&gt;我的音乐&lt;/router-link&gt;</span></span>
<span class="line"><span>	&lt;router-link to=&quot;/part&quot;&gt;朋友&lt;/router-link&gt;</span></span>
<span class="line"><span>&lt;/div&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 二者是相等的</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;div class=&quot;footer_wrap&quot;&gt;</span></span>
<span class="line"><span>	&lt;a href=&quot;#/find&quot;&gt;发现音乐&lt;/a&gt;</span></span>
<span class="line"><span>	&lt;a href=&quot;#/my&quot;&gt;我的音乐&lt;/a&gt;</span></span>
<span class="line"><span>	&lt;a href=&quot;#/part&quot;&gt;朋友&lt;/a&gt;</span></span>
<span class="line"><span>&lt;/div&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>一般使用路由的场景大都会用到高亮显示,vue已经在router-link中封装好了高亮的逻辑,我们只需要提供高亮样式 在设置高亮样式时使用<code>router-link-active</code>和<code>router-link-exect-active</code>两个类名都可以</p><p><strong>两个高亮类名的区别</strong></p><ol><li>router-link-active模糊匹配(用的多） to=&quot;/my&quot; 可以匹配/my /my/a /my/b</li><li>router-link-exact-active精确匹配 to=&quot;/my&quot;仅可以匹配/my</li></ol><p><strong>自定义高亮类名</strong> 可以在VueRouter对象中设置自定义的高亮类名</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const router=new VueRouter({</span></span>
<span class="line"><span>	linkActiveClass:&#39;active&#39;,</span></span>
<span class="line"><span>	linkExactActiveClass:&#39;exact-active&#39;</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="跳转传参" tabindex="-1"><a class="header-anchor" href="#跳转传参"><span>跳转传参</span></a></h3><p>在跳转路由时，进行传值</p><p>查询参数传参</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>to=&quot;/path?参数名=值&quot;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>在对应的页面组件中获取参数</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>$route.query.参数名</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="动态路由传参" tabindex="-1"><a class="header-anchor" href="#动态路由传参"><span>动态路由传参</span></a></h4><ol><li>配置动态路由</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const router = new VueRouter({</span></span>
<span class="line"><span>	routes:[</span></span>
<span class="line"><span>		{</span></span>
<span class="line"><span>			path:&#39;/search/:words&#39;,</span></span>
<span class="line"><span>			component:Search</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	]</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>:words是动态参数,跳转到/search下的哪个网页就代表的是那个网页的路由名 可以获取words值解析出对应页面的路由名</p><ol start="2"><li>配置导航链接</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>to=&quot;/path/参数值&quot;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="3"><li>对应页面组件接收传递过来的值</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>$route.params.words</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h5 id="动态路由可选符" tabindex="-1"><a class="header-anchor" href="#动态路由可选符"><span>动态路由可选符</span></a></h5><p>配了路由<code>path:&quot;/search/:words&quot;</code>后跳转到/search路由页面中会未匹配到组件，显示空白 原因是<code>/search/:words</code>表示，必须要传参数。如果不传参数，也希望匹配，可以加个可选符&quot;？&quot;</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>{ path: &#39;/search/:words?&quot;,component:Search}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="重定向" tabindex="-1"><a class="header-anchor" href="#重定向"><span>重定向</span></a></h2><p>进入到一个路径中后强制跳转到其他路径</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//{path:匹配路径，redirect:重定向到的路径},</span></span>
<span class="line"><span>const router = new VueRouter({</span></span>
<span class="line"><span>routes:[</span></span>
<span class="line"><span>		{ path:&#39;/&#39;,redirect:&#39;/home&#39;},</span></span>
<span class="line"><span>		{path:&#39;/home&#39;,component:Home },</span></span>
<span class="line"><span>		{path:&#39;/search/:words&#39;,component:Search}</span></span>
<span class="line"><span>	]</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_404" tabindex="-1"><a class="header-anchor" href="#_404"><span>404</span></a></h2><p>404错误码还是很常见的,主要用于用户进入到没有设置的路径时返回404</p><p>404路由要配置在路由的最后面 <code>path:&quot;*&quot;</code>(任意路径）前面不匹配就命中最后这个</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const router = new VueRouter({</span></span>
<span class="line"><span>	routes:[</span></span>
<span class="line"><span>		{ path:&#39;/&#39;,redirect:&#39;/home&#39;},</span></span>
<span class="line"><span>		path:&#39;/home&#39;,component:Home },</span></span>
<span class="line"><span>		path: &#39;/search/:words?&#39;. component: Search },</span></span>
<span class="line"><span>		path:&quot;*&quot;,component:NotFind }</span></span>
<span class="line"><span>	]</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="模式设置" tabindex="-1"><a class="header-anchor" href="#模式设置"><span>模式设置</span></a></h2><p>路由的路径看起来不自然，有#，切换成真正路径形式 hash路由(默认)例如：http://localhost:8080/#/home history路由(常用)例如：http://localhost:8080/home（以后上线需要服务器端支持） 只需要将模式设置为history即可</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const router = new VueRouter({</span></span>
<span class="line"><span>	routes,</span></span>
<span class="line"><span>	mode: &quot;history&quot;</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="编程式导航" tabindex="-1"><a class="header-anchor" href="#编程式导航"><span>编程式导航</span></a></h2><p>点击按钮实现跳转 用js代码来进行跳转</p><h3 id="push跳转" tabindex="-1"><a class="header-anchor" href="#push跳转"><span>push跳转</span></a></h3><p>push跳转会保留历史记录 <strong>path路径跳转</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//简单形式</span></span>
<span class="line"><span>this.$router.push（&#39;路由路径&#39;）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>//完整形式</span></span>
<span class="line"><span>this.$router.push({</span></span>
<span class="line"><span>	path:&#39;路由路径&#39;</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>name命名路由跳转</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>{name：&#39;路由名&#39;,path:&#39;/path/xxx&#39;,component:xxx}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="传参" tabindex="-1"><a class="header-anchor" href="#传参"><span>传参</span></a></h3><p><strong>path路径跳转传参</strong> 跳转传参可以手动拼接,也可以使用特定的语法让vue进行拼接后的路径传参</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>this.$router.push（&#39;路由路径？参数名=参数值&#39;）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>this.$router.push({</span></span>
<span class="line"><span>	path：‘路由路径‘</span></span>
<span class="line"><span>	query:{</span></span>
<span class="line"><span>		参数名：参数值，</span></span>
<span class="line"><span>		参数名：参数值</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>获取参数值时通过<code>$route.query.参数名</code>获取 <strong>name命名路由跳转传参</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>this.$router.push({</span></span>
<span class="line"><span>	name:&#39;路由名&#39;</span></span>
<span class="line"><span>	params:{</span></span>
<span class="line"><span>		参数名：参数值，</span></span>
<span class="line"><span>		参数名：参数值</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>获取参数值时通过<code>$route.params.参数名</code>获取</p><h3 id="replace跳转" tabindex="-1"><a class="header-anchor" href="#replace跳转"><span>replace跳转</span></a></h3><p>replace跳转不会保存历史记录</p><h3 id="子路由" tabindex="-1"><a class="header-anchor" href="#子路由"><span>子路由</span></a></h3><p>在一个路由下面还可以配置哪个路由下的子路由 在那个路由下添加children属性,children中路由配置和routes一样</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span> routes: [</span></span>
<span class="line"><span>    {</span></span>
<span class="line"><span>      path: &#39;/&#39;,</span></span>
<span class="line"><span>      component: Layout,</span></span>
<span class="line"><span>      children:[</span></span>
<span class="line"><span>	        {</span></span>
<span class="line"><span>	          path: &#39;/article&#39;,</span></span>
<span class="line"><span>	          component: Article</span></span>
<span class="line"><span>	        },</span></span>
<span class="line"><span>	        {</span></span>
<span class="line"><span>	          path: &#39;/collect&#39;,</span></span>
<span class="line"><span>	          component: Collect</span></span>
<span class="line"><span>	        }</span></span>
<span class="line"><span>	    ]</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><h2 id="组件缓存" tabindex="-1"><a class="header-anchor" href="#组件缓存"><span>组件缓存</span></a></h2><p>问题：点击路由地址后跳转到新的路径返回时数据又重新加载;了 原因：路由跳转后，组件被销毁了，返回回来组件又被重建了，所以数据重新被加载了 解决：利用keep-alive将组件缓存下来</p><h3 id="keep-alive" tabindex="-1"><a class="header-anchor" href="#keep-alive"><span>keep-alive</span></a></h3><p>keep-alive是Vue的内置组件，当它包裹动态组件时，会缓存不活动的组件实例，而不是销毁它们。 keep-alive是一个抽象组件：它自身不会渲染成一个DOM元素，也不会出现在父组件链中。</p><p>在组件切换过程中把切换出去的组件保留在内存中，防止重复渲染DOM 减少加载时间及性能消耗，提高用户体验性。</p><p>使用时只需要使用<code>&lt;keep-alive&gt;</code>标签将要缓存的标签包裹起来</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;template&gt;</span></span>
<span class="line"><span>  &lt;div class=&quot;h5-wrapper&quot;&gt;</span></span>
<span class="line"><span>    &lt;keep-alive&gt;</span></span>
<span class="line"><span>      &lt;router-view&gt;&lt;/router-view&gt;</span></span>
<span class="line"><span>    &lt;/keep-alive&gt;</span></span>
<span class="line"><span>  &lt;/div&gt;</span></span>
<span class="line"><span>&lt;/template&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>keep-alive默认会将包裹的所有内容都缓存,如果有不需要缓存的地方需要使用它的三个属性来排除</p><ul><li>include : 组件名数组,只有匹配的组件会被缓存</li><li>exclude : 组件名数组,任何匹配的组件都不会被缓存</li><li>max : 最多可以缓存多少组件实例</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;template&gt;</span></span>
<span class="line"><span>  &lt;div class=&quot;h5-wrapper&quot;&gt;</span></span>
<span class="line"><span>    &lt;keep-alive :include=&quot;[&#39;comp1&#39;,&#39;comp2&#39;]&quot;&gt;</span></span>
<span class="line"><span>      &lt;router-view&gt;&lt;/router-view&gt;</span></span>
<span class="line"><span>    &lt;/keep-alive&gt;</span></span>
<span class="line"><span>  &lt;/div&gt;</span></span>
<span class="line"><span>&lt;/template&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="生命周期" tabindex="-1"><a class="header-anchor" href="#生命周期"><span>生命周期</span></a></h3><p>当一个组件被设置缓存后它会多两个生命周期</p><ul><li>actived : 激活时</li><li>deactive : 失活时</li></ul><h2 id="路由前置导航守卫" tabindex="-1"><a class="header-anchor" href="#路由前置导航守卫"><span>路由前置导航守卫</span></a></h2><p>任何路由在跳转前都有经过前置导航守卫 在beforeEach函数中</p><ul><li>to是要跳转到的路径</li><li>from是原本路径</li><li>next是一个函数用于处理放行或不放行 next()是放行 next(&#39;路径&#39;)是调转到给定路径</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const authUrls = [&#39;/pay&#39;, &#39;/myOrder&#39;]</span></span>
<span class="line"><span>router.beforeEach((to, from, next) =&gt; {</span></span>
<span class="line"><span>  if (!authUrls.includes(to.path)) {</span></span>
<span class="line"><span>    next()</span></span>
<span class="line"><span>    return</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>  const token = store.getters.token</span></span>
<span class="line"><span>  if (token) {</span></span>
<span class="line"><span>    next()</span></span>
<span class="line"><span>  } else {</span></span>
<span class="line"><span>    next(&#39;/login&#39;)</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="router4" tabindex="-1"><a class="header-anchor" href="#router4"><span>router4</span></a></h2><p>在vue3中使用的是router4版本,配置和router3版本略有不同</p><p>创建路由使用<code>createRouter</code>函数 <code>createWebHistory</code>是history模式<code>createHashHistory</code>是hash模式 传入的参数是基础路径,此路由下的所有路径都是基础路径后面的 meta.env.BASE_URL是vite中配置的基础路径</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const router = createRouter({</span></span>
<span class="line"><span>	history:createWebHistory(import.meta.env.BASE_URL),</span></span>
<span class="line"><span>	routes:[]</span></span>
<span class="line"><span>)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,125)]))}const r=e(l,[["render",d]]),c=JSON.parse('{"path":"/front/vue/3/","title":"3 自定义","lang":"zh-CN","frontmatter":{"title":"3 自定义","createTime":"2025/05/04 17:19:50","permalink":"/front/vue/3/"},"readingTime":{"minutes":7.91,"words":2374},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/vue/3 自定义.md","headers":[]}');export{r as comp,c as data};
